#!/usr/bin/env node
/**
 * E2E test script for device signer flows.
 * All keys (public + private) are generated by the script — no external keys needed.
 *
 * Flow 1 — Device signer created together with the wallet:
 *   CROSSMINT_API_KEY=xxx node scripts/e2e-device-signer.mjs 1
 *
 * Flow 2 — Device signer added after wallet creation:
 *   CROSSMINT_API_KEY=xxx node scripts/e2e-device-signer.mjs 2
 *
 * Required env var:
 *   CROSSMINT_API_KEY  — Staging server-side API key
 */

import { webcrypto, createPrivateKey, sign as nodeSign } from "node:crypto";
import { generatePrivateKey, privateKeyToAccount } from "viem/accounts";

const crypto = webcrypto;

// ─── Config ──────────────────────────────────────────────────────────────────

const API_BASE = "https://staging.crossmint.com/api/2025-06-09";
const FUND_BASE = "https://staging.crossmint.com/api/v1-alpha2";
const CHAIN = "base-sepolia";
const TOKEN = "base-sepolia:usdxm";
// Admin signer address used in both flows (external-wallet — no admin signing needed by the script)
const ADMIN_SIGNER_ADDRESS = "0x05a29d789231c290de91cc62e6dbf220894a7a6c";
const RECIPIENT = "0xc9b888e8f2c9c60f72f84e97e4416c3aca3e1f7c";
const AMOUNT = "0.0001";
const POLL_INTERVAL_MS = 3_000;
const POLL_TIMEOUT_MS = 120_000;

// ─── Logging helpers ─────────────────────────────────────────────────────────

function log(step, msg, data) {
    console.log(`\n[${step}] ${msg}`);
    if (data !== undefined) console.log(JSON.stringify(data, null, 2));
}

function fail(step, msg, data) {
    console.error(`\n❌ [${step}] FAILED: ${msg}`);
    if (data !== undefined) console.error(JSON.stringify(data, null, 2));
    process.exit(1);
}

// ─── API helper ──────────────────────────────────────────────────────────────

async function apiCall(method, path, body, apiKey, baseUrl = API_BASE) {
    const url = `${baseUrl}/${path}`;
    log("http", `${method} ${url}`, body ?? undefined);
    const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json", "x-api-key": apiKey },
        body: body !== undefined ? JSON.stringify(body) : undefined,
    });
    const json = await res.json();
    if (json?.error || !res.ok) {
        fail("http", `${method} ${url} → ${json?.message ?? JSON.stringify(json)}`, json);
    }
    return json;
}

// ─── Polling helper ──────────────────────────────────────────────────────────

async function poll(label, fetcher, isDone) {
    const start = Date.now();
    while (Date.now() - start < POLL_TIMEOUT_MS) {
        await new Promise((r) => setTimeout(r, POLL_INTERVAL_MS));
        const result = await fetcher();
        log("poll", `[${label}] status: ${result?.status}`);
        if (result?.status === "failed") fail("poll", `${label} failed`, result);
        if (isDone(result)) return result;
    }
    fail("poll", `${label} timed out after ${POLL_TIMEOUT_MS}ms`);
}

// ─── Crypto helpers ──────────────────────────────────────────────────────────

/**
 * Generate a P-256 key pair.
 * Returns privateKey (CryptoKey), publicKey as decimal x/y strings,
 * and a hex credentialId (compressed public key hex, used as a unique ID).
 * The signer locator is NOT computed here — it comes from the API response.
 */
async function generateDeviceKey() {
    const { publicKey, privateKey } = await crypto.subtle.generateKey(
        { name: "ECDSA", namedCurve: "P-256" },
        true,
        ["sign", "verify"]
    );

    // exportKey("raw") → [0x04, x(32 bytes), y(32 bytes)] = 65 bytes (uncompressed)
    const raw = new Uint8Array(await crypto.subtle.exportKey("raw", publicKey));
    const xBytes = raw.slice(1, 33);
    const yBytes = raw.slice(33, 65);

    function bytesToDecimal(b) {
        return BigInt(
            "0x" +
                Array.from(b)
                    .map((n) => n.toString(16).padStart(2, "0"))
                    .join("")
        ).toString(10);
    }

    const xDecimal = bytesToDecimal(xBytes);
    const yDecimal = bytesToDecimal(yBytes);

    // Locator: device:<base64(uncompressed_65_bytes)>  — standard base64, matches the API format
    const locator = `device:${Buffer.from(raw).toString("base64")}`;

    // Hex of compressed public key — used as a unique passkey credential ID
    const y = BigInt(yDecimal);
    const prefix = y % 2n === 0n ? 0x02 : 0x03;
    const xHex = BigInt(xDecimal).toString(16).padStart(64, "0");
    const compressed = Buffer.concat([Buffer.from([prefix]), Buffer.from(xHex, "hex")]);
    const credentialId = compressed.toString("hex");

    return {
        privateKey,
        publicKey: { x: xDecimal, y: yDecimal },
        locator,
        credentialId,
    };
}

/**
 * Parse a DER-encoded ECDSA signature into { r, s } Buffers (each up to 32 bytes).
 */
function parseDERSig(der) {
    let pos = 0;
    if (der[pos++] !== 0x30) throw new Error("DER: expected SEQUENCE");
    let totalLen = der[pos++];
    if (totalLen & 0x80) {
        const nBytes = totalLen & 0x7f;
        totalLen = 0;
        for (let i = 0; i < nBytes; i++) totalLen = (totalLen << 8) | der[pos++];
    }
    if (der[pos++] !== 0x02) throw new Error("DER: expected INTEGER (r)");
    const rLen = der[pos++];
    let r = der.slice(pos, pos + rLen);
    pos += rLen;
    if (der[pos++] !== 0x02) throw new Error("DER: expected INTEGER (s)");
    const sLen = der[pos++];
    let s = der.slice(pos, pos + sLen);
    // Strip DER sign-extension leading zero
    while (r.length > 1 && r[0] === 0) r = r.slice(1);
    while (s.length > 1 && s[0] === 0) s = s.slice(1);
    return { r, s };
}

/**
 * Sign a message with a P-256 device key using RAW ECDSA (no additional SHA-256 hashing).
 * The message/challenge is treated as a pre-hash value — equivalent to EIP-7212 P256Verify.
 * Message may be hex ("0x...") or base64 — both are handled.
 * Returns { r, s } as 0x-prefixed 32-byte hex strings.
 */
async function signWithDevice(privateKey, message) {
    const messageBytes = message.startsWith("0x")
        ? Buffer.from(message.slice(2), "hex")
        : Buffer.from(message, "base64");

    // Export the WebCrypto key as PKCS8 DER and wrap as a Node.js KeyObject
    const pkcs8Der = await crypto.subtle.exportKey("pkcs8", privateKey);
    const nodeKey = createPrivateKey({ key: Buffer.from(pkcs8Der), format: "der", type: "pkcs8" });

    // crypto.sign(null, data, key) = raw ECDSA: treats data as the pre-computed hash,
    // no additional SHA-256 is applied. Returns a DER-encoded signature.
    const derSig = nodeSign(null, messageBytes, nodeKey);

    const { r, s } = parseDERSig(Buffer.from(derSig));
    const toHex32 = (b) => "0x" + b.toString("hex").padStart(64, "0");
    return { r: toHex32(r), s: toHex32(s) };
}

// ─── Locator helper ──────────────────────────────────────────────────────────

/**
 * Fetch the wallet and return the locator of the most recently added delegated signer.
 * This avoids any client-side locator computation — the API is the source of truth.
 */
async function fetchLastSignerLocator(walletAddress, apiKey) {
    const wallet = await apiCall("GET", `wallets/${walletAddress}`, undefined, apiKey);
    const signers = wallet?.config?.delegatedSigners;
    if (!Array.isArray(signers) || signers.length === 0) {
        fail("fetchSigner", "No delegated signers found in wallet", wallet);
    }
    const locator = signers[signers.length - 1]?.locator;
    if (!locator) fail("fetchSigner", "Delegated signer has no locator", signers);
    log("fetchSigner", `Device signer locator: ${locator}`);
    return locator;
}

// ─── API steps ───────────────────────────────────────────────────────────────

/**
 * Flow 1: create wallet with external-wallet admin + device delegated signer.
 * Admin signer is a fixed address — no admin signing needed in this flow.
 * Signer locator is fetched from the wallet after creation.
 */
async function createWalletWithDeviceSigner(deviceKey, apiKey) {
    const owner = `userId:e2e-flow1-${Date.now()}`;
    const res = await apiCall(
        "POST",
        "wallets",
        {
            chainType: "evm",
            type: "smart",
            config: {
                adminSigner: { type: "external-wallet", address: ADMIN_SIGNER_ADDRESS },
                delegatedSigners: [
                    {
                        signer: { type: "device", publicKey: deviceKey.publicKey },
                        chain: CHAIN,
                    },
                ],
            },
            owner,
        },
        apiKey
    );

    if (!res.address) fail("createWallet", "No address in response", res);
    log("createWallet", `✓ Wallet created: ${res.address}`);

    // Fetch the wallet to get the API-assigned signer locator
    const signerLocator = await fetchLastSignerLocator(res.address, apiKey);
    return { walletAddress: res.address, signerLocator };
}

/**
 * Generate a secp256k1 (EVM) key pair for use as the wallet admin in Flow 2.
 * Returns a viem Account object that can sign Ethereum messages.
 */
function generateAdminKey() {
    const privateKey = generatePrivateKey();
    const account = privateKeyToAccount(privateKey);
    log("adminKey", `Generated admin address: ${account.address}`);
    return account; // has .address and .signMessage()
}

/**
 * Flow 2: create wallet with a freshly generated external-wallet admin.
 * The admin key is generated in the script so it can sign the add-signer approval.
 */
async function createWalletWithExternalAdmin(adminAddress, apiKey) {
    const owner = `userId:e2e-flow2-${Date.now()}`;
    const res = await apiCall(
        "POST",
        "wallets",
        {
            chainType: "evm",
            type: "smart",
            config: {
                adminSigner: { type: "external-wallet", address: adminAddress },
            },
            owner,
        },
        apiKey
    );

    if (!res.address) fail("createWallet", "No address in response", res);
    log("createWallet", `✓ Wallet created: ${res.address}`);
    return res.address;
}

async function fundWallet(walletAddress, apiKey) {
    await apiCall(
        "POST",
        `wallets/${walletAddress}/balances`,
        { amount: 1, token: "usdxm", chain: CHAIN },
        apiKey,
        FUND_BASE
    );
    log("fundWallet", "Fund request sent, waiting 5s for settlement...");
    await new Promise((r) => setTimeout(r, 5_000));
}

/**
 * Add a device signer to an existing wallet.
 * The admin (external-wallet) signs the approval using Ethereum personal_sign,
 * matching the SDK's EVMExternalWalletSigner.signMessage() behavior exactly.
 * Returns the API-assigned locator from the create-signer response.
 */
async function addDeviceSigner(walletAddress, deviceKey, adminAccount, apiKey) {
    const res = await apiCall(
        "POST",
        `wallets/${walletAddress}/signers`,
        {
            signer: { type: "device", publicKey: deviceKey.publicKey },
            chain: CHAIN,
        },
        apiKey
    );
    log("addSigner", "Response", res);

    // The API-assigned device locator (e.g. "device:BEjk...")
    const deviceLocator = res?.locator ?? deviceKey.locator;
    log("addSigner", `Device locator: ${deviceLocator}`);

    // EVM response shape: { chains: { "base-sepolia": { id, status, approvals: { pending: [...] } } } }
    const chainData = res?.chains?.[CHAIN];
    if (!chainData?.id) fail("addSigner", `No signature ID for chain ${CHAIN}`, res);

    const signatureId = chainData.id;
    log("addSigner", `Signature ID: ${signatureId}  status: ${chainData.status}`);

    if (chainData.status === "success") {
        log("addSigner", "Already approved — no signing needed");
    } else if (chainData.status === "pending") {
        await poll(
            "add-signer",
            () => apiCall("GET", `wallets/${walletAddress}/signatures/${signatureId}`, undefined, apiKey),
            (r) => r?.status === "success"
        );
    } else {
        // "awaiting-approval" — the admin (external-wallet) must authorize the add-signer.
        // The SDK's EVMExternalWalletSigner.signMessage() uses Ethereum personal_sign:
        //   signature = personal_sign(message, adminPrivKey)  →  "0x<r32><s32><v1>"
        // Get the pending approval message from the initial response, or fall back to GET.
        let pendingApproval = chainData.approvals?.pending?.[0];
        if (!pendingApproval) {
            const sigReq = await apiCall(
                "GET",
                `wallets/${walletAddress}/signatures/${signatureId}`,
                undefined,
                apiKey
            );
            pendingApproval = sigReq?.approvals?.pending?.[0];
            if (!pendingApproval) fail("addSigner", "No pending approvals found", sigReq);
        }

        const message = pendingApproval.message;
        const expectedSigner = pendingApproval.signer?.locator;
        log("addSigner", `Challenge: ${message}`);
        log("addSigner", `Expected signer: ${expectedSigner}`);
        log("addSigner", "Signing with admin key (Ethereum personal_sign)...");

        // personal_sign: keccak256("\x19Ethereum Signed Message:\n32" + msgBytes)
        // viem's signMessage({ message: { raw } }) does exactly this
        const sig = await adminAccount.signMessage({ message: { raw: message } });
        log("addSigner", `Admin signature: ${sig.slice(0, 20)}...`);

        const adminLocator = `external-wallet:${adminAccount.address}`;
        await apiCall(
            "POST",
            `wallets/${walletAddress}/signatures/${signatureId}/approvals`,
            { approvals: [{ signer: adminLocator, signature: sig }] },
            apiKey
        );

        log("addSigner", "Approval submitted, waiting for confirmation...");
        await poll(
            "add-signer",
            () => apiCall("GET", `wallets/${walletAddress}/signatures/${signatureId}`, undefined, apiKey),
            (r) => r?.status === "success"
        );
    }

    log("addSigner", `✓ Device signer added: ${deviceLocator}`);
    return deviceLocator;
}

async function createTransfer(walletAddress, signerLocator, apiKey) {
    const tx = await apiCall(
        "POST",
        `wallets/${walletAddress}/tokens/${TOKEN}/transfers`,
        { recipient: RECIPIENT, signer: signerLocator, amount: AMOUNT },
        apiKey
    );
    log("transfer", "Transfer created", tx);

    const txId = tx?.id;
    if (!txId) fail("transfer", "No transaction ID in response", tx);

    // Pending approvals may already be in the initial response
    let pending = tx?.approvals?.pending;
    if (!pending?.length) {
        log("transfer", "Fetching transaction to get pending approvals...");
        const full = await apiCall(
            "GET",
            `wallets/${walletAddress}/transactions/${txId}`,
            undefined,
            apiKey
        );
        pending = full?.approvals?.pending;
    }

    if (!pending?.length) fail("transfer", "No pending approvals for transaction", tx);

    const approval = pending[0];
    if (!approval.message) fail("transfer", "No message in pending approval", approval);

    return {
        txId,
        message: approval.message,
        approvalSignerLocator: approval.signer?.locator ?? signerLocator,
    };
}

async function approveTransfer(walletAddress, txId, signerLocator, message, devicePrivateKey, apiKey) {
    log("approveTransfer", "Signing message with device key...");
    const { r, s } = await signWithDevice(devicePrivateKey, message);
    log("approveTransfer", `Signature: r=${r.slice(0, 12)}...  s=${s.slice(0, 12)}...`);

    await apiCall(
        "POST",
        `wallets/${walletAddress}/transactions/${txId}/approvals`,
        { approvals: [{ signer: signerLocator, signature: { r, s } }] },
        apiKey
    );

    log("approveTransfer", "Approval submitted, waiting for on-chain confirmation...");
    const finalTx = await poll(
        "transfer",
        () => apiCall("GET", `wallets/${walletAddress}/transactions/${txId}`, undefined, apiKey),
        (r) => r?.status === "success"
    );

    log("approveTransfer", "✓ Transfer confirmed!");
    if (finalTx?.onChain?.txId) log("approveTransfer", `Tx hash:   ${finalTx.onChain.txId}`);
    if (finalTx?.onChain?.explorerLink) log("approveTransfer", `Explorer:  ${finalTx.onChain.explorerLink}`);
    return finalTx;
}

// ─── Flow 1: device signer created with the wallet ───────────────────────────

async function flow1(apiKey) {
    console.log("\n╔═══════════════════════════════════════════════════════╗");
    console.log("║  FLOW 1 — Device signer on wallet creation            ║");
    console.log("╚═══════════════════════════════════════════════════════╝\n");

    log("1/7", "Generating P-256 device key pair...");
    const deviceKey = await generateDeviceKey();
    log("1/7", "Public key", deviceKey.publicKey);

    log("2/7", "Creating wallet with device signer...");
    const { walletAddress, signerLocator } = await createWalletWithDeviceSigner(deviceKey, apiKey);

    log("3/7", "Funding wallet...");
    await fundWallet(walletAddress, apiKey);

    log("4/7", "Creating transfer transaction...");
    const { txId, message, approvalSignerLocator } = await createTransfer(
        walletAddress,
        signerLocator,
        apiKey
    );

    log("5-6/7", "Signing and submitting approval with device key...");
    await approveTransfer(walletAddress, txId, approvalSignerLocator, message, deviceKey.privateKey, apiKey);

    console.log("\n✅  FLOW 1 COMPLETE\n");
}

// ─── Flow 2: device signer added after wallet creation ───────────────────────

async function flow2(apiKey) {
    console.log("\n╔═══════════════════════════════════════════════════════╗");
    console.log("║  FLOW 2 — Device signer added after wallet creation   ║");
    console.log("╚═══════════════════════════════════════════════════════╝\n");

    log("1/7", "Generating admin (secp256k1) and device (P-256) key pairs...");
    const adminAccount = generateAdminKey();
    const deviceKey = await generateDeviceKey();
    log("1/7", `Admin address: ${adminAccount.address}`);
    log("1/7", "Device public key", deviceKey.publicKey);

    log("2/7", "Creating wallet with generated external-wallet admin...");
    const walletAddress = await createWalletWithExternalAdmin(adminAccount.address, apiKey);

    log("3-4/7", "Adding device signer (admin signs the approval with Ethereum personal_sign)...");
    const deviceSignerLocator = await addDeviceSigner(walletAddress, deviceKey, adminAccount, apiKey);

    log("5/7", "Funding wallet...");
    await fundWallet(walletAddress, apiKey);

    log("6/7", "Creating transfer transaction via device signer...");
    const { txId, message, approvalSignerLocator } = await createTransfer(
        walletAddress,
        deviceSignerLocator,
        apiKey
    );

    log("7/7", "Signing and submitting transfer approval with device key...");
    await approveTransfer(walletAddress, txId, approvalSignerLocator, message, deviceKey.privateKey, apiKey);

    console.log("\n✅  FLOW 2 COMPLETE\n");
}

// ─── Entry point ─────────────────────────────────────────────────────────────

const flow = process.argv[2];
const apiKey = process.env.CROSSMINT_API_KEY;

if (!apiKey) {
    console.error("Error: CROSSMINT_API_KEY environment variable is required");
    process.exit(1);
}

if (!flow || !["1", "2"].includes(flow)) {
    console.error("Usage:");
    console.error("  CROSSMINT_API_KEY=xxx node scripts/e2e-device-signer.mjs 1");
    console.error("  CROSSMINT_API_KEY=xxx node scripts/e2e-device-signer.mjs 2");
    process.exit(1);
}

try {
    if (flow === "1") await flow1(apiKey);
    else await flow2(apiKey);
} catch (e) {
    console.error("\n❌ Unexpected error:", e?.message ?? e);
    if (e?.stack) console.error(e.stack);
    process.exit(1);
}
